1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PRICE_BY_ITEM_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	type Customer = { yearsWithMHPCO: number };
14	
15	const basePriceFor = (item: Item): number =>
16	  BASE_PRICE_BY_ITEM_TYPE[item.type] ?? 0;
17	
18	const priceForItem = (item: Item): number => {
19	  const basePrice = basePriceFor(item);
20	  return basePrice + basePrice * FIRST_INSURANCE_SURCHARGE_RATE;
21	};
22	
23	export const quote = (_customer: Customer, items: Item[]): number => {
24	  const itemsTotal = items.reduce((sum, item) => sum + priceForItem(item), 0);
25	  return Math.ceil(itemsTotal + PROCESSING_FEE);
26	};
27	
28	export const claim = (..._args: unknown[]): unknown => {
29	  return undefined;
30	};
